export default defineScript({
  init() {
    return { t: 0 };
  },

  update(self, dt) {
    self.t = self.t + dt;
    if (self.t <= 1) {
      const startpos = vmath.vector3(0, 600, 0);
      const endpos = vmath.vector3(600, 0, 0);
      const pos = vmath.lerp(self.t, startpos, endpos);
      go.set_position(pos, "go");
    }
  },
});

